        tile[8] += sc * Ux[3] * Uy[1] * Uz[2];
        tile[9] += sc * Ux[3] * Uy[0] * Uz[3];
        tile[10] += sc * Ux[4] * Uy[4] * Uz[0];
        tile[11] += sc * Ux[4] * Uy[3] * Uz[1];
        tile[12] += sc * Ux[4] * Uy[2] * Uz[2];
        tile[13] += sc * Ux[4] * Uy[1] * Uz[3];
