            acc[109] += scale * (Gx[2]) * (Gy[1] * yij + Gy[8]) * (Gz[8]);
            acc[110] += scale * (Gx[2]) * (Gy[0] * yij + Gy[7]) * (Gz[9]);
            acc[111] += scale * (Gx[1]) * (Gy[3] * yij + Gy[10]) * (Gz[7]);
