  tile[37] = 0.0;
  tile[38] = 0.0;
  tile[39] = 0.0;
  tile[40] = 0.0;
  tile[41] = 0.0;
  tile[42] = 0.0;
  tile[43] = 0.0;
  tile[44] = 0.0;
